        "-H", "accept: application/json, text/event-stream",
        "-H", "Content-Type: application/json",
        "-d", payload
    ]
    result = subprocess.run(cmd, capture_output=True, text=True)
    output = result.stdout
    if "data:" in output:
        data_str = output.split("data: ")[1]
        try:
            data = json.loads(data_str)
            content = data.get('result', {}).get('content', [])
            for c in content:
                text = c.get('text', '')
                if text.startswith('['):
                    products = json.loads(text)
                    for p in products:
                        pid = p.get('ProductId', '')
                        if pid:
                            all_products[pid] = p
        except Exception as e:
            print(f"Page {page} error: {e}")

print(f"Total unique products: {len(all_products)}")

# Apply filters
filtered = []
for pid, p in all_products.items():
    try:
        sales = p.get('SalesCount', 0)
        price = p.get('Price', 0)
        rating = p.get('Ratings', 0)
        sale_time = p.get('SaleTime', '')

        if price < 50 or price > 350:
            continue
        if rating < 4.0:
            continue
        if sales < 30:
            continue

        if sale_time:
            try:
                st = datetime.strptime(sale_time, "%Y-%m-%d")
                age_months = (now - st).days / 30
                if age_months > 12:
                    continue
            except:
                continue

        # Check if it's hair accessory related
        title = p.get('Title', '').lower()
        # Keep if any known hair accessory keyword in title
        hair_kw = ['กิ๊บ', 'โบว์', 'ริบบิ้น', 'คลิป', 'ยางรัด', 'หวี', 'ประดับ', 'ผม', 'hair', 'clip', 'bow', 'ribbon', 'pin']
        if not any(kw in title for kw in hair_kw):
            continue

        filtered.append(p)
    except:
        pass

print(f"Hair accessories after filters: {len(filtered)}")

# Save combined with previous results
prev = []
try:
    with open('/tmp/th_hair_all.json') as f:
        prev = json.load(f)
except:
    pass

# Merge
prev_pids = {p.get('ProductId', '') for p in prev}
for p in filtered:
    if p.get('ProductId', '') not in prev_pids:
        prev.append(p)

print(f"Combined total: {len(prev)}")

with open('/tmp/th_hair_all.json', 'w') as f:
    json.dump(prev, f, ensure_ascii=False)
